import{_ as a,H as s,f as o,i as t}from"./chunks/framework.DbTCwA-u.js";const g=JSON.parse(`{"title":"Dépannage","description":"Problèmes courants et solutions lors de l'utilisation d'EligiusNametag.","frontmatter":{"title":"Dépannage","description":"Problèmes courants et solutions lors de l'utilisation d'EligiusNametag."},"headers":[],"relativePath":"fr/troubleshooting.md","filePath":"fr/troubleshooting.md"}`),r={name:"fr/troubleshooting.md"};function n(i,e,l,u,d,c){return s(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="depannage-troubleshooting" tabindex="-1">Dépannage (Troubleshooting) <a class="header-anchor" href="#depannage-troubleshooting" aria-label="Permalink to &quot;Dépannage (Troubleshooting)&quot;">​</a></h1><p>Vous rencontrez des problèmes avec EligiusNametag ? Consultez ces solutions courantes :</p><h3 id="_1-le-nametag-n-apparait-pas-au-dessus-du-joueur" tabindex="-1">1. Le Nametag n&#39;apparaît pas au-dessus du joueur <a class="header-anchor" href="#_1-le-nametag-n-apparait-pas-au-dessus-du-joueur" aria-label="Permalink to &quot;1. Le Nametag n&#39;apparaît pas au-dessus du joueur&quot;">​</a></h3><ul><li><strong>Avez-vous installé ProtocolLib ?</strong> Notre plugin repose strictement sur l&#39;injection de paquets pour que les nametags flottent en douceur sans causer de lag.</li><li><strong>Avez-vous installé PlaceholderAPI ?</strong> Si vous utilisez des variables comme <code>%vault_rank%</code> et que vous n&#39;avez pas PAPI, le texte pourrait ne pas s&#39;afficher.</li></ul><h3 id="_2-erreur-database-connection-closed" tabindex="-1">2. Erreur &quot;Database Connection Closed&quot; <a class="header-anchor" href="#_2-erreur-database-connection-closed" aria-label="Permalink to &quot;2. Erreur &quot;Database Connection Closed&quot;&quot;">​</a></h3><ul><li>Ce problème a été <strong>corrigé dans les versions récentes</strong>. Assurez-vous d&#39;utiliser la dernière version <code>v1.x.x</code> ou supérieure. Si vous utilisez <strong>MySQL</strong>, vérifiez que l&#39;IP et les identifiants dans <code>config.yml</code> sont corrects. Sinon, utilisez <code>SQLITE</code> localement.</li></ul><h3 id="_3-avertissements-viaversion-dans-la-console" tabindex="-1">3. Avertissements ViaVersion dans la Console <a class="header-anchor" href="#_3-avertissements-viaversion-dans-la-console" aria-label="Permalink to &quot;3. Avertissements ViaVersion dans la Console&quot;">​</a></h3><p>Si vous utilisez ViaVersion pour permettre aux joueurs en 1.20 de rejoindre votre serveur 1.21+, vous pourriez voir des messages concernant les <em>Metadata</em> et <em>Protocol Versions</em>.</p><ul><li><strong>Cause :</strong> L&#39;ancien client (ex. 1.20.2) ne possède pas le code natif pour traiter correctement les grandes entités <code>TEXT_DISPLAY</code>.</li><li><strong>Solution :</strong> Nous recommandons vivement d&#39;exiger des versions 1.21+ pour une visualisation parfaite des hologrammes, ou ignorez simplement l&#39;avertissement si le joueur ne rencontre aucun plantage visuel.</li></ul><h3 id="_4-enametag-lang-ne-met-pas-a-jour-le-message-d-aide" tabindex="-1">4. /enametag lang ne met pas à jour le message d&#39;aide <a class="header-anchor" href="#_4-enametag-lang-ne-met-pas-a-jour-le-message-d-aide" aria-label="Permalink to &quot;4. /enametag lang ne met pas à jour le message d&#39;aide&quot;">​</a></h3><p>Lors de l&#39;utilisation de <code>/enametag lang fr</code>, le plugin lit à partir de <code>lang/fr.yml</code>. Si vous remarquez qu&#39;une traduction est vide ou qu&#39;une commande agit bizarrement, vous pouvez supprimer le dossier <code>lang/</code> dans votre répertoire de plugins afin qu&#39;EligiusNametag puisse le regénérer proprement avec les dernières normes.</p>',11)])])}const p=a(r,[["render",n]]);export{g as __pageData,p as default};
